using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _pool;
    private readonly string[] _labels;

    public TicketController(
        PredictionEnginePool<TicketData, TicketPrediction> pool,
        IConfiguration configuration)
    {
        _pool = pool;

        var modelPath = configuration["ModelPath"]!;
        var mlContext = new MLContext();
        var model = mlContext.Model.Load(modelPath, out var schema);

        var transformer = (model as ITransformer)!;
        var outputSchema = transformer.GetOutputSchema(schema);
        var scoreColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        _labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority is < 1 or > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

